"""Auto Seam UV Equalizer Blender add-on."""

from __future__ import annotations

bl_info = {
    "name": "Auto Seam UV Equalizer",
    "author": "Generated by Codex",
    "version": (0, 2, 0),
    "blender": (4, 0, 0),
    "location": "View3D > Sidebar > Auto UV",
    "description": "Automatically mark seams and unwrap selected mesh objects.",
    "category": "UV",
}

import bpy
from bpy.props import PointerProperty

from . import operators, properties, seam_detection, ui, uv_tools

CLASSES = (
    properties.AUTOSEAMUV_PG_settings,
    operators.AUTOSEAMUV_OT_mark_only,
    operators.AUTOSEAMUV_OT_unwrap_only,
    operators.AUTOSEAMUV_OT_auto_unwrap_pack,
    operators.AUTOSEAMUV_OT_mark_and_unwrap,
    operators.AUTOSEAMUV_OT_atlas_pack_selected_objects,
    operators.AUTOSEAMUV_OT_clear_seams,
    ui.AUTOSEAMUV_PT_panel,
)


def register() -> None:
    """Register add-on classes and scene properties."""
    for cls in CLASSES:
        bpy.utils.register_class(cls)

    bpy.types.Scene.autoseamuv_settings = PointerProperty(type=properties.AUTOSEAMUV_PG_settings)


def unregister() -> None:
    """Unregister add-on classes and scene properties."""
    if hasattr(bpy.types.Scene, "autoseamuv_settings"):
        del bpy.types.Scene.autoseamuv_settings

    for cls in reversed(CLASSES):
        bpy.utils.unregister_class(cls)


if __name__ == "__main__":
    register()
